declare @invoke nvarchar(4000)
select @invoke = ''
&ListDeleted;
&PostDeleted;
select @invoke as invoke






        /* <flatten type="Javascript"> */
var f = this, id = f.get_id(), v = f._language == 'v', g = f.getItem('d43')._controlBehavior;
var e1 = (v ? 'Thông tin mã khách của phiếu thu hoặc hóa đơn phải giống với chứng từ phân bổ.' : 'Customer Information of voucher receipt or sales invoice should have same customer information as voucher allocation.');
var e2 = (v ? 'Thông tin tài khoản của phiếu thu phải giống với hóa đơn.' : 'Account information of voucher receipt should have same account information as sales invoice.');
var l1 = g._getColumnOrder('ma_kh_phieu'), l2 = g._getColumnOrder('ma_kh_hd'), k1 = g._getColumnOrder('tk'), k2 = g._getColumnOrder('tk_du');
var t = f.getItemValue('ma_kh'), ctag = g._getColumnOrder('tag'), ftag = false;
for (var i = 1; i <= g._rowCount; i++) {
  var u = g._getItemValue(i, l1), u2 = g._getItemValue(i, l2), tag = g._getItemValue(i, ctag);
  if (tag && (t != u || t != u2)) {
    $func.hideWait(id);
    $message.show(e1, String.format('$find(\'{0}\').getItem(\'ma_kh\').focus()', id));
    f._checked = false;
    break;
  }
  if (f._checked && f._account$Allcation) {
    if (((tag && f._callFromOther) || !f._callFromOther) && $func.trim(g._getItemValue(i, k1)) != $func.trim(g._getItemValue(i, k2))) {
      f._errorWarningObject = g._getItem(i, g._getColumnOrder('so_phieu'));
      $func.hideWait(id);
      $message.show(e2, String.format('var f = $find(\'{0}\');f.focus(\'d43\');f._errorWarningObject.focus()', id));
      f._checked = false;
      break;
    }
  }
  if (tag) ftag = true;
}
if (f._checked && f._callFromOther && !ftag) {
  var e3 = (v ? 'Chưa có bản ghi nào được chọn, phải đánh dấu trước khi thực hiện chức năng này.' : 'No record selected, please select at least one record to process.');
  f._errorWarningObject = g._getItem(1, ctag);
  $message.show(e3, String.format('var f = $find(\'{0}\');f.focus(\'d43\');f._errorWarningObject.focus()', id));
  f._checked = false;
}
/* </flatten> */
        &ListChecking;
