script.text:
      &ScriptVoucherInit;
      &ScriptVoucherNumber;
      /* <flatten type="Javascript"> */
function init$Voucher$(f) {}
function create$Voucher$(f) {
  var g = f.grid, pg = g._parentGrid;
  if (pg && pg._controller == 'ARMultiAllocation') {
    f._callFromOther = true;
  } else {
    f._callFromOther = false;
  }
}
/* </flatten> */
function active$Voucher$(f) {
  objectBehavior$Voucher$Number.create(f, 'so_ct', 'ma_nk', 'ngay_ct', 'ma_dvcs');
  f.add_onResponseComplete(on$Voucher$ResponseComplete);
  f.add_commandEvent(on$Voucher$ExecuteCommand);
  f._tabContainer.add_activeTabChanged(onChange$Voucher$Tab);
  f._tabContainer._loaded = true;
  set$Voucher$DefaultValue(f);
  set$Voucher$DefaultFromPayment(f);
  &ListCreate;
  &PostCreate;
}
/* <flatten type="Javascript"> */
function scatter$Voucher$(f) {
  f._voucherNumberBehavior.setFormLayout();
  set$Voucher$DefaultValue(f);
  set$Voucher$DefaultFromPayment(f);
}
/* </flatten> */
function close$Voucher$(f) {
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onChange$Voucher$Tab);} catch (ex) {}
  try {f.remove_commandEvent(on$Voucher$ExecuteCommand);} catch (ex) {}
  try {f.remove_onResponseComplete(on$Voucher$ResponseComplete);} catch (ex) {}
  objectBehavior$Voucher$Number.dispose(f);
  &ListDispose;
  &PostDispose;
}
function on$Voucher$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender, g = f.getItem('d43')._controlBehavior;
  switch (action) {
    case 'Save':
      break;
    case 'Check':
      break;
    case 'Gather':
      g.setSequenceNumber('line_nbr');
      g.setContinuance('stt_rec0');
      break;
    case 'Shown':
      &ListShown;
      &PostShown;
      break;
    default:
      break;
  }
}
function on$Voucher$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Loading':
      &VoucherNumberLoading;
      break;
    case 'Scattering':
      &VoucherNumberScattering;
      &ListScattering;
      &PostScattering;
      break;

      &VoucherNumberReading;

    case 'Customer':
      f.setItemControlBehavior('dia_chi', result[0].Value, null, false);
      break;
    case 'Navigating':
      &ListRefresh;
      &PostRefresh;
      break;
    &ListResponseTicket;
    default:
        break;
  }
}
function onChange$Voucher$Tab(sender, e) {
  sender.parentForm.focusWhenTabChanged(['d43'&ListTabChange;&PostTabChange;]);
  &PostTabFocus;
}
/* <flatten type="Javascript"> */
function onChange$Voucher$Customer(o) {
  var f = o.parentForm;
  change$Voucher$Customer$KeyFilter(f);
  f.request('Customer', 'Customer', ['ma_kh'], o);
}
function onChange$Voucher$Date(o) {
  var f = o.parentForm;
  f.setItemValue('ngay_ct', f.getItemValue('ngay_lct'));
  change$Voucher$Customer$KeyFilter(f);
}
function set$Voucher$DefaultValue(f) {
  if (f._action == 'New') {
    var d = new Date();
    f.setItemValue('ngay_lct', d);
    f.setItemValue('ngay_ct', d);
  }
}
function change$Voucher$Customer$KeyFilter(f) {
  set$Voucher$Customer$KeyFilter(f, 'so_phieu');
  set$Voucher$Customer$KeyFilter(f, 'so_hd');
}
function set$Voucher$Customer$KeyFilter(f, c) {
  var g = f.getItem('d43')._controlBehavior, o = g._activeCell, l = g._getColumnOrder(c);
  if (l == g._activeColumn) {
    if (o._controlBehavior) {
      var fields = g._fields, field = g._fields[l - 1], r = o.row, id = g.get_id();
      if (field.ItemKeyFilter) o._controlBehavior.set_completionKeyFilter($func.completionFilter(o, fields, field.ItemKeyFilter, r, id));
      if (field.ItemCheckFilter) o._controlBehavior.set_completionCheckFilter($func.completionFilter(o, fields, field.ItemCheckFilter, r, id));
    }
  }
}

function set$Voucher$DefaultFromPayment(f) {
  if (f._callFromOther) {
    var m = f.grid._memvars;
    for(var i = 0; i < m.length; i++) {
      if (m[i].Name == 'ext_key' && m[i].NewValue != '') {
        f._extKey = m[i].NewValue;
        if (f._action == 'New') {
          var pg = f.grid._parentGrid;
          f.setItemValues('ma_dvcs, ma_kh, ten_kh%l', [pg._getItemValue(pg._activeRow, pg._getColumnOrder('ma_dvcs')), pg._getItemValue(pg._activeRow, pg._getColumnOrder('ma_kh')), pg._getItemValue(pg._activeRow, pg._getColumnOrder('ten_kh%l'))]);
          f.request('Customer', 'Customer', ['ma_kh']);
        }
        break;
      }
    }
  }
}
/* </flatten> */
